"use strict";(self.webpackChunkzio_nats_docs=self.webpackChunkzio_nats_docs||[]).push([[816],{9300(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","href":"/zio-nats/quickstart","label":"Quick start","docId":"quickstart","unlisted":false},{"type":"category","label":"Guides","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/zio-nats/guides/pubsub","label":"Pub/Sub","docId":"guides/pubsub","unlisted":false},{"type":"link","href":"/zio-nats/guides/serialization","label":"Serialization","docId":"guides/serialization","unlisted":false},{"type":"link","href":"/zio-nats/guides/jetstream","label":"JetStream","docId":"guides/jetstream","unlisted":false},{"type":"link","href":"/zio-nats/guides/service","label":"Service Framework","docId":"guides/service","unlisted":false},{"type":"link","href":"/zio-nats/guides/key-value","label":"Key-Value Store","docId":"guides/key-value","unlisted":false},{"type":"link","href":"/zio-nats/guides/object-store","label":"Object Store","docId":"guides/object-store","unlisted":false},{"type":"link","href":"/zio-nats/guides/connection-events","label":"Connection Events","docId":"guides/connection-events","unlisted":false},{"type":"link","href":"/zio-nats/guides/configuration","label":"Configuration","docId":"guides/configuration","unlisted":false},{"type":"link","href":"/zio-nats/guides/testing","label":"Testing","docId":"guides/testing","unlisted":false}]},{"type":"category","label":"Internals","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/zio-nats/concepts/construction","label":"Layer Construction","docId":"concepts/construction","unlisted":false},{"type":"link","href":"/zio-nats/concepts/lifetimes","label":"Resource Lifetimes","docId":"concepts/lifetimes","unlisted":false}]},{"type":"category","label":"Reference","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/zio-nats/reference/nats-config","label":"NatsConfig Reference","docId":"reference/nats-config","unlisted":false},{"type":"link","href":"/zio-nats/reference/error-handling","label":"Error Handling","docId":"reference/error-handling","unlisted":false},{"type":"link","href":"/zio-nats/reference/modules","label":"Modules","docId":"reference/modules","unlisted":false}]},{"type":"link","href":"/zio-nats/","label":"zio-nats","docId":"index","unlisted":false}]},"docs":{"concepts/construction":{"id":"concepts/construction","title":"Layer Construction","description":"Every zio-nats feature is a ZLayer. Knowing the dependency tree tells you which layers to pass to .provide and what each one requires - this page is a reference for wiring any combination of services together.","sidebar":"docs"},"concepts/lifetimes":{"id":"concepts/lifetimes","title":"Resource Lifetimes","description":"Every zio-nats resource - connections, subscriptions, consumers, watch streams, services - has a well-defined lifetime tied to a ZIO Scope. When the scope closes, the resource is released automatically, whether the scope ended normally, with an error, or due to fiber interruption. This page explains where each resource lives and what cleanup happens when it is released.","sidebar":"docs"},"guides/configuration":{"id":"guides/configuration","title":"Configuration","description":"NatsConfig holds every connection setting for the NATS client - server addresses, authentication, TLS, reconnect behaviour, and socket tuning. Build it directly in code for static deployments, or let ZIO\'s built-in config system load it from environment variables or a HOCON file for environment-driven ones. Either way, the same Nats.live layer accepts the result.","sidebar":"docs"},"guides/connection-events":{"id":"guides/connection-events","title":"Connection Events","description":"Nats#lifecycleEvents is a ZStream[Any, Nothing, NatsEvent] that fires whenever the underlying TCP connection changes state - connecting, disconnecting, reconnecting, and closing. The stream never fails; exceptions from the client internals are wrapped in NatsEvent.ExceptionOccurred rather than surfacing as stream errors. Multiple concurrent subscribers are supported and each receives a full independent copy of the event stream.","sidebar":"docs"},"guides/jetstream":{"id":"guides/jetstream","title":"JetStream","description":"JetStream is the persistence layer of NATS. Where Core NATS delivers messages at-most-once and forgets them, JetStream stores messages in server-side streams - named logs that capture every message published to a set of subjects. Consumers are named cursors into a stream; each consumer tracks its position independently and the server remembers it across restarts. This gives you at-least-once delivery by default, exactly-once delivery with message deduplication, and the ability to replay historical messages from any point.","sidebar":"docs"},"guides/key-value":{"id":"guides/key-value","title":"Key-Value Store","description":"The NATS Key-Value store is a named bucket of key-value pairs where every write creates a new revision. The full history of each key is preserved up to a configurable limit, giving you versioned storage with the ability to read past values, watch for changes in real time, and resume a watch after a restart without missing updates. KV is built on JetStream streams under the hood - the same persistence, replication, and delivery guarantees apply.","sidebar":"docs"},"guides/object-store":{"id":"guides/object-store","title":"Object Store","description":"The NATS Object Store provides named binary storage in a bucket, with automatic chunking for arbitrarily large objects. A 10-byte config file and a 2 GB video use the same API - NATS handles splitting and reassembling the chunks transparently. Like the Key-Value store, Object Store is built on JetStream streams and supports metadata, soft deletes, and a watch stream that notifies you when objects change.","sidebar":"docs"},"guides/pubsub":{"id":"guides/pubsub","title":"Pub/Sub","description":"Publishing","sidebar":"docs"},"guides/serialization":{"id":"guides/serialization","title":"Serialization","description":"All Nats#publish, Nats#subscribe, and Nats#request methods are generic over A: NatsCodec]. The codec is resolved at compile time - no casting, no runtime lookup, and no separate encode/decode step in your code. zio-nats comes batteries-included with zio-blocks, jsoniter-scala, and play-json integrations, and if none of those fit you can [bring your own in a few lines.","sidebar":"docs"},"guides/service":{"id":"guides/service","title":"Service Framework","description":"The NATS Service Framework (also called the Micro protocol) turns any set of request-reply handlers into a discoverable microservice with zero extra infrastructure. Services announce themselves over standard NATS subjects, respond to ping, info, and stats queries from any client on the cluster, and load-balance requests across multiple instances automatically via queue groups. There are no sidecars, no service registries, and no additional network hops - discovery and routing are built into NATS itself.","sidebar":"docs"},"guides/testing":{"id":"guides/testing","title":"Testing","description":"zio-nats-testkit starts a real NATS server in a Docker container via testcontainers and provides a wired Nats layer pointing at it. There are no mocks to maintain and no manual server setup - your tests run against the same protocol your production code uses.","sidebar":"docs"},"index":{"id":"index","title":"zio-nats","description":"Overview","sidebar":"docs"},"quickstart":{"id":"quickstart","title":"Quick start","description":"Prerequisites","sidebar":"docs"},"reference/error-handling":{"id":"reference/error-handling","title":"Error Handling","description":"NatsError is a sealed ADT - every error zio-nats can produce is one of the variants below. All operations return IO[NatsError, A], so the compiler knows exactly which errors are possible at each call site.","sidebar":"docs"},"reference/modules":{"id":"reference/modules","title":"Modules","description":"zio-nats is split across several artifacts. Most projects need only one of the two main options below - zio-nats for batteries-included, or zio-nats-core when you want to bring your own serialization.","sidebar":"docs"},"reference/nats-config":{"id":"reference/nats-config","title":"NatsConfig Reference","description":"Full field reference for NatsConfig. For usage examples - auth, TLS, environment variables, HOCON - see the Configuration guide.","sidebar":"docs"}}}}')}}]);